rss.channel:
{{ name }}
{{ site_url }}
{{ description }}
{{ lang }}
{% if events %}{{ events[0].last_updated_at | rfc2822 }}{% endif %}

{% for event in events %}


  {% if event.title_cn %}{{ event.title_cn }}{% else %}{{ event.title }}{% endif %}
  {{ site_url }}/event/{{ event.id }}
  {% if event.summary_cn %}{{ event.summary_cn }}{% elif event.summary_en %}{{ event.summary_en }}{% else %}{{ event.description }}{% endif %}
  {{ event.last_updated_at | rfc2822 }}
  {{ site_url }}/event/{{ event.id }}

{% endfor %}
